      if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT) {
        APFloat LowerBound = *C;
        LowerBound.next(/*nextDown=*/true);
        // Average of C and LowerBound
        APFloat Boundary = *C;
        Boundary.add(LowerBound, APFloat::rmNearestTiesToEven);
        Boundary.divide(APFloat(DstSem, "2.0"), APFloat::rmNearestTiesToEven);
        bool Lossy;
        APFloat Test = Boundary;
        Test.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
        if (!Lossy) {
           return new FCmpInst(Pred, X, ConstantFP::get(X->getType(), Boundary), "", &I);
        }
      }
CODEEOF

